import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { 
  X, Play, Pause, ScrollText, ChevronRight, Sparkles, 
  RefreshCw, BookOpen, Volume2, SkipBack, SkipForward, 
  ArrowLeft, Search, Bookmark, History, LayoutGrid, 
  Library, Trophy, Target, Type, Mic2, FileText, 
  Compass, Feather, User, Menu, Sliders
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { SanZiJingVerse, CharAnalysis } from '../lib/sanzijingData';
import { GoogleGenAI } from "@google/genai";
import sql from '../lib/neon';

type ViewType = 'hub' | 'reader' | 'stories' | 'profile';

const ThreeCharacterApp: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const [verses, setVerses] = useState<SanZiJingVerse[]>([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [currentCharIdx, setCurrentCharIdx] = useState(-1);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentView, setCurrentView] = useState<ViewType>('hub');
  const [activeTab, setActiveTab] = useState<'study' | 'source' | 'lexicon' | 'ai'>('study');
  const [isLoading, setIsLoading] = useState(true);
  const [selectedCharDetail, setSelectedCharDetail] = useState<CharAnalysis | null>(null);
  const [aiInsight, setAiInsight] = useState<string>('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [showPinyin, setShowPinyin] = useState(true);
  const [isVertical, setIsVertical] = useState(true);
  const [stats, setStats] = useState({ learned: 124, streak: 5, points: 850 });

  const scrollRef = useRef<HTMLDivElement>(null);
  const verseRefs = useRef<(HTMLDivElement | null)[]>([]);

  // 语音播报
  const speak = (text: string, rate: number = 0.8) => {
    if (!window.speechSynthesis) return;
    window.speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = 'zh-CN';
    utterance.rate = rate;
    window.speechSynthesis.speak(utterance);
  };

  const fetchData = useCallback(async () => {
    if (!sql) return;
    setIsLoading(true);
    try {
      const data = await sql`SELECT * FROM sanzijing_verses ORDER BY verse_index ASC`;
      if (data && data.length > 0) {
        const formatted = data.map(d => ({
          ...d,
          content_chars: Array.isArray(d.content_chars) ? d.content_chars : [],
          content_pinyin: Array.isArray(d.content_pinyin) ? d.content_pinyin : [],
          key_vocabulary: Array.isArray(d.key_vocabulary) ? d.key_vocabulary : [],
          tags: Array.isArray(d.tags) ? d.tags : [],
          char_analysis: typeof d.char_analysis === 'string' ? JSON.parse(d.char_analysis) : d.char_analysis
        })) as SanZiJingVerse[];
        setVerses(formatted);
      }
    } catch (e) {
      console.error("Fetch Error:", e);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => { fetchData(); }, [fetchData]);

  const fetchAiInsight = async (verse: SanZiJingVerse) => {
    if (isAiLoading || !verse) return;
    setIsAiLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `你是一位温和的国学老师。请针对这段经文：“${verse.content_raw}”，给孩子写一段简短、有趣的生活建议。100字以内。`,
      });
      setAiInsight(response.text || '智慧正在生成中...');
    } catch (e) {
      setAiInsight('AI 老师去休息啦，待会再试吧。');
    } finally {
      setIsAiLoading(false);
    }
  };

  useEffect(() => {
    if (activeTab === 'ai' && !aiInsight && verses[currentIdx]) {
      fetchAiInsight(verses[currentIdx]);
    }
  }, [activeTab, currentIdx, verses]);

  const playVerseSequence = useCallback((idx: number) => {
    if (!window.speechSynthesis || !verses[idx]) return;
    window.speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(verses[idx].content_raw);
    utterance.lang = 'zh-CN';
    utterance.rate = 0.75;

    utterance.onboundary = (e) => {
      const textBefore = verses[idx].content_raw.substring(0, e.charIndex);
      const chineseOnlyBefore = textBefore.replace(/[^\u4e00-\u9fa5]/g, '');
      setCurrentCharIdx(chineseOnlyBefore.length);
    };

    utterance.onend = () => {
      setCurrentCharIdx(-1);
      if (isPlaying && idx < verses.length - 1) {
        setTimeout(() => isPlaying && setCurrentIdx(idx + 1), 1000);
      } else {
        setIsPlaying(false);
      }
    };
    window.speechSynthesis.speak(utterance);
  }, [isPlaying, verses]);

  useEffect(() => {
    if (isPlaying) playVerseSequence(currentIdx);
    verseRefs.current[currentIdx]?.scrollIntoView({ behavior: 'smooth', block: 'center' });
    setAiInsight('');
  }, [currentIdx, isPlaying, playVerseSequence]);

  const activeVerse = verses[currentIdx];

  // 渲染分发
  const renderView = () => {
    switch (currentView) {
      case 'hub': return <HubView />;
      case 'reader': return <ReaderView />;
      case 'stories': return <StoriesView />;
      case 'profile': return <ProfileView />;
    }
  };

  // --- 视图组件: 首页枢纽 ---
  function HubView() {
    const dailyIdx = useMemo(() => new Date().getDate() % (verses.length || 1), []);
    const dailyVerse = verses[dailyIdx];

    return (
      <motion.div 
        initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
        className="flex-1 flex flex-col p-6 md:p-12 overflow-y-auto no-scrollbar"
      >
        <div className="flex justify-between items-start mb-12">
          <div>
             <h2 className="text-3xl md:text-5xl font-black text-[#1A1A1A] serif-font mb-2">晨诵 · 三字经</h2>
             <p className="text-slate-400 font-bold tracking-[0.2em] text-xs">温故而知新，可以为师矣。</p>
          </div>
          <div className="flex items-center gap-4">
             <div className="text-right">
                <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest">学习进度</div>
                <div className="text-lg font-black text-[#B22222]">85%</div>
             </div>
             <div className="w-12 h-12 bg-[#B22222] rounded-full flex items-center justify-center text-white shadow-xl shadow-[#B22222]/20">
                <User size={24} />
             </div>
          </div>
        </div>

        {/* 每日金句卡片 */}
        <div className="relative mb-12 group cursor-pointer" onClick={() => { setCurrentIdx(dailyIdx); setCurrentView('reader'); }}>
          <div className="absolute inset-0 bg-[#B22222]/5 rounded-[3rem] blur-3xl opacity-50 group-hover:opacity-100 transition-opacity" />
          <div className="relative bg-white/80 backdrop-blur-xl border border-[#e0d7c6] rounded-[2.5rem] md:rounded-[4rem] p-10 md:p-20 shadow-xl overflow-hidden">
             <div className="absolute top-10 right-10 opacity-[0.03] rotate-12 transition-transform duration-1000 group-hover:rotate-45">
                <Feather size={300} />
             </div>
             <div className="flex flex-col md:flex-row items-center gap-8 md:gap-16">
                <div className="flex flex-col items-center">
                   <div className="text-[10px] font-black text-[#B22222] bg-[#B22222]/10 px-3 py-1 rounded-full mb-6 tracking-widest">每日金句</div>
                   <div className="text-7xl md:text-9xl font-black text-[#1A1A1A] tracking-tighter serif-font leading-none">
                     {dailyVerse?.content_chars.slice(0, 3).join('')}
                   </div>
                </div>
                <div className="flex-1 text-center md:text-left">
                   <p className="text-xl md:text-3xl text-slate-600 leading-relaxed font-bold italic mb-8 serif-font">
                     “{dailyVerse?.translation_vernacular}”
                   </p>
                   <button className="px-8 py-3 bg-[#1A1A1A] text-white rounded-full text-xs font-black uppercase tracking-widest hover:bg-[#B22222] transition-all flex items-center gap-2 mx-auto md:mx-0">
                     开始研读 <ChevronRight size={16} />
                   </button>
                </div>
             </div>
          </div>
        </div>

        {/* 金刚区按钮 */}
        <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
           <HubCard icon={<BookOpen size={24}/>} label="全书阅读" sub="Immersive Read" onClick={() => setCurrentView('reader')} />
           <HubCard icon={<Compass size={24}/>} label="典故探索" sub="Historical Tales" onClick={() => setCurrentView('stories')} />
           <HubCard icon={<Trophy size={24}/>} label="成长印记" sub="Achievements" onClick={() => setCurrentView('profile')} />
           <HubCard icon={<RefreshCw size={24}/>} label="语音跟读" sub="Voice Practice" onClick={() => { setCurrentView('reader'); setIsPlaying(true); }} />
        </div>
      </motion.div>
    );
  }

  // --- 视图组件: 沉浸式阅读器 ---
  function ReaderView() {
    return (
      <motion.div initial={{ x: 50, opacity: 0 }} animate={{ x: 0, opacity: 1 }} className="flex-1 flex flex-col lg:flex-row overflow-hidden">
        {/* 左侧经文 */}
        <section className="flex-1 flex flex-col min-h-0 border-r border-[#e0d7c6] relative overflow-hidden bg-white/30">
          <div className="flex items-center justify-between p-6 shrink-0 z-20">
             <button onClick={() => setCurrentView('hub')} className="p-3 bg-white border border-[#e0d7c6] rounded-2xl text-slate-400 hover:text-[#B22222] transition-all shadow-sm">
                <ArrowLeft size={20} />
             </button>
             <div className="flex gap-2">
                <ReaderAction icon={<Type size={18}/>} active={showPinyin} onClick={() => setShowPinyin(!showPinyin)} />
                <ReaderAction icon={<LayoutGrid size={18}/>} active={isVertical} onClick={() => setIsVertical(!isVertical)} />
             </div>
          </div>

          <div className="flex-1 overflow-y-auto p-8 md:p-16 space-y-24 no-scrollbar scroll-smooth">
            {verses.map((v, i) => (
              <div 
                key={v.id} ref={el => { verseRefs.current[i] = el; }}
                onClick={() => { setIsPlaying(false); setCurrentIdx(i); speak(v.content_raw); }}
                className={`transition-all duration-700 cursor-pointer flex justify-center group ${currentIdx === i ? 'opacity-100' : 'opacity-10 blur-[0.5px] hover:opacity-40'}`}
              >
                <div className={`flex ${isVertical ? 'flex-row-reverse' : 'flex-col'} gap-8 md:gap-16 relative py-12 px-12 border-x border-[#B22222]/10`}>
                  <div className="absolute top-0 left-0 w-full h-px bg-[#B22222]/20" />
                  <div className="absolute bottom-0 left-0 w-full h-px bg-[#B22222]/20" />

                  {/* 分组显示 */}
                  <div className={`flex flex-wrap justify-center gap-x-12 md:gap-x-20 gap-y-12 max-w-[500px]`}>
                    {v.content_chars.map((char, cIdx) => (
                      <div key={cIdx} className="flex flex-col items-center">
                        {showPinyin && (
                          <span className={`text-[10px] md:text-sm font-mono mb-2 ${currentIdx === i && currentCharIdx === cIdx ? 'text-[#B22222] font-black' : 'text-slate-300'}`}>
                            {v.content_pinyin[cIdx]}
                          </span>
                        )}
                        <span className={`text-6xl md:text-[9rem] font-black leading-none transition-all serif-font ${currentIdx === i && currentCharIdx === cIdx ? 'text-[#1A1A1A] drop-shadow-2xl scale-110' : 'text-slate-200'}`}>
                          {char}
                        </span>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            ))}
            <div className="h-60" />
          </div>

          {/* 悬浮控制台 */}
          <div className="absolute bottom-10 left-1/2 -translate-x-1/2 z-40 w-[300px] md:w-[400px]">
            <div className="bg-[#1A1A1A]/90 backdrop-blur-2xl rounded-full p-2.5 flex items-center justify-between shadow-2xl border border-white/10">
               <button onClick={() => setCurrentIdx(prev => Math.max(0, prev - 1))} className="p-4 text-white/50 hover:text-white"><SkipBack size={24} fill="currentColor" /></button>
               <button onClick={() => setIsPlaying(!isPlaying)} className="w-16 h-16 bg-white rounded-full flex items-center justify-center shadow-lg active:scale-90 transition-all">
                 {isPlaying ? <Pause size={32} className="text-[#1A1A1A]" fill="currentColor" /> : <Play size={32} className="text-[#1A1A1A] ml-1" fill="currentColor" />}
               </button>
               <button onClick={() => setCurrentIdx(prev => Math.min(verses.length - 1, prev + 1))} className="p-4 text-white/50 hover:text-white"><SkipForward size={24} fill="currentColor" /></button>
            </div>
          </div>
        </section>

        {/* 右侧解析面板 */}
        <aside className="lg:w-[480px] xl:w-[560px] flex flex-col bg-white shadow-[-40px_0_100px_rgba(0,0,0,0.02)] z-30">
          <nav className="flex bg-[#FDFBF7] border-b border-[#e0d7c6]">
            {['study', 'source', 'lexicon', 'ai'].map((tab: any) => (
              <button
                key={tab} onClick={() => setActiveTab(tab)}
                className={`flex-1 py-6 flex flex-col items-center gap-1.5 text-[11px] font-black transition-all relative ${activeTab === tab ? 'text-[#B22222] bg-white' : 'text-slate-400 hover:bg-slate-50'}`}
              >
                {tab === 'study' ? <BookOpen size={16}/> : tab === 'source' ? <History size={16}/> : tab === 'lexicon' ? <Search size={16}/> : <Sparkles size={16}/>}
                {tab === 'study' ? '义理' : tab === 'source' ? '典故' : tab === 'lexicon' ? '字解' : 'AI'}
                {activeTab === tab && <motion.div layoutId="tab-active" className="absolute bottom-0 w-full h-1 bg-[#B22222]" />}
              </button>
            ))}
          </nav>

          <div className="flex-1 overflow-y-auto p-8 md:p-12 space-y-12 no-scrollbar">
            <AnimatePresence mode="wait">
              {activeTab === 'study' && (
                <motion.div key="study" initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} className="space-y-12">
                   <section>
                      <h3 className="text-[10px] font-black text-slate-300 uppercase tracking-widest mb-6 italic serif-font">现代译文</h3>
                      <p className="text-3xl font-black text-[#1A1A1A] leading-tight italic serif-font">“{activeVerse?.translation_vernacular}”</p>
                   </section>
                   <section className="bg-[#f9f6f0] p-8 rounded-[2rem] border border-[#e0d7c6] shadow-sm">
                      <h3 className="text-[10px] font-black text-[#B22222] uppercase tracking-[0.3em] mb-8 italic">深度导读</h3>
                      <p className="text-lg text-slate-600 leading-loose font-medium text-justify">
                        {activeVerse?.interpretation_deep}
                      </p>
                   </section>
                </motion.div>
              )}
              {activeTab === 'ai' && (
                <motion.div key="ai" initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="space-y-8">
                   <div className="p-10 bg-emerald-50/50 border border-emerald-100 rounded-[3.5rem] relative overflow-hidden shadow-sm">
                      <div className="flex items-center justify-between mb-10 text-emerald-600">
                        <div className="flex items-center gap-4"><Mic2 size={24} /> <h4 className="text-[10px] font-black uppercase tracking-[0.5em] italic">AI 老师的生活智慧</h4></div>
                      </div>
                      {isAiLoading ? (
                        <div className="py-20 flex flex-col items-center gap-6"><Loader2 className="w-12 h-12 text-emerald-500 animate-spin" /><p className="text-[10px] text-emerald-400 font-black tracking-[0.3em]">AI 正在查阅古籍...</p></div>
                      ) : (
                        <div className="animate-in fade-in duration-1000">
                           <p className="text-3xl font-bold text-emerald-900 leading-snug italic mb-12 serif-font">“{aiInsight}”</p>
                           <div className="bg-emerald-900 text-white p-8 rounded-3xl flex items-center gap-6 shadow-2xl">
                              <Target size={32} className="text-emerald-300 shrink-0" />
                              <p className="text-sm font-medium leading-relaxed opacity-90 italic">这是专门为你准备的今日建议，记得在生活中尝试一下哦！</p>
                           </div>
                        </div>
                      )}
                   </div>
                </motion.div>
              )}
              {/* 其他 Tab 渲染逻辑在此添加 */}
            </AnimatePresence>
          </div>
        </aside>
      </motion.div>
    );
  }

  // --- 视图组件: 典故探索 ---
  function StoriesView() {
    return (
      <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="flex-1 p-6 md:p-12 overflow-y-auto no-scrollbar">
         <div className="flex items-center gap-6 mb-12">
            <button onClick={() => setCurrentView('hub')} className="p-3 bg-white border border-[#e0d7c6] rounded-2xl"><ArrowLeft/></button>
            <h2 className="text-4xl font-black serif-font text-[#1A1A1A]">典故汇编</h2>
         </div>
         <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {verses.filter(v => v.allusion_title).map(v => (
              <div key={v.id} className="bg-white border border-[#e0d7c6] rounded-[2.5rem] p-8 hover:shadow-2xl transition-all cursor-pointer group">
                 <div className="flex justify-between items-start mb-6">
                    <div className="px-4 py-1 bg-[#B22222]/5 text-[#B22222] rounded-full text-[10px] font-black">{v.allusion_source}</div>
                    <Star size={16} className="text-slate-200 group-hover:text-amber-400 transition-colors" />
                 </div>
                 <h3 className="text-2xl font-black text-[#1A1A1A] mb-4 serif-font group-hover:text-[#B22222] transition-colors">{v.allusion_title}</h3>
                 <p className="text-slate-500 text-sm leading-relaxed italic mb-8 line-clamp-3">“{v.allusion_context}”</p>
                 <div className="pt-6 border-t border-[#f3efe6] flex justify-between items-center opacity-0 group-hover:opacity-100 transition-opacity">
                    <span className="text-[10px] font-black uppercase tracking-widest text-[#B22222]">阅读全文</span>
                    <ChevronRight size={16} className="text-[#B22222]" />
                 </div>
              </div>
            ))}
         </div>
      </motion.div>
    );
  }

  // --- 视图组件: 个人成就 ---
  function ProfileView() {
    return (
      <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="flex-1 p-6 md:p-12 overflow-y-auto no-scrollbar">
         <button onClick={() => setCurrentView('hub')} className="mb-8 p-3 bg-white border border-[#e0d7c6] rounded-2xl"><ArrowLeft/></button>
         <div className="max-w-4xl mx-auto">
            <div className="flex flex-col md:flex-row items-center gap-10 mb-16">
               <div className="w-32 h-32 bg-[#1A1A1A] rounded-full flex items-center justify-center text-white text-5xl font-black shadow-2xl">修</div>
               <div className="text-center md:text-left flex-1">
                  <h2 className="text-4xl font-black serif-font mb-2">学而时习之</h2>
                  <p className="text-slate-400 font-bold italic">已在知识通国学馆修行 {stats.streak} 日</p>
               </div>
               <div className="grid grid-cols-3 gap-6">
                  <StatBox label="已学汉字" value={stats.learned} />
                  <StatBox label="连续打卡" value={stats.streak} />
                  <StatBox label="国学积分" value={stats.points} />
               </div>
            </div>

            <h3 className="text-xl font-black serif-font mb-8 border-b border-[#e0d7c6] pb-4">勋章墙</h3>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
               <Badge icon="🖋️" label="笔耕不辍" />
               <Badge icon="墨" label="墨韵留芳" active />
               <Badge icon="📜" label="博闻强识" active />
               <Badge icon="砚" label="铁杵磨针" />
            </div>
         </div>
      </motion.div>
    );
  }

  return (
    <div className="fixed inset-0 z-[60] bg-[#F9F6F0] flex flex-col font-serif select-none overflow-hidden pb-[env(safe-area-inset-bottom)]">
      <div className="absolute inset-0 opacity-[0.06] pointer-events-none z-0 bg-[url('https://www.transparenttextures.com/patterns/rice-paper.png')]" />

      <AnimatePresence mode="wait">
        {renderView()}
      </AnimatePresence>

      {isLoading && (
        <div className="fixed inset-0 z-[100] bg-[#F9F6F0] flex flex-col items-center justify-center">
          <Loader2 className="w-12 h-12 text-[#B22222] animate-spin mb-4" />
          <p className="text-xs font-black tracking-[0.4em] text-[#B22222] uppercase">开启全息经文长卷...</p>
        </div>
      )}

      <style>{`
        .serif-font { font-family: 'Noto Serif SC', serif; }
        .no-scrollbar::-webkit-scrollbar { display: none; }
      `}</style>
    </div>
  );
};

const HubCard = ({ icon, label, sub, onClick }: any) => (
  <button onClick={onClick} className="bg-white border border-[#e0d7c6] p-8 rounded-[2.5rem] flex flex-col items-center gap-4 hover:border-[#B22222] hover:shadow-xl transition-all group">
     <div className="w-16 h-16 bg-[#f9f6f0] rounded-2xl flex items-center justify-center text-slate-400 group-hover:text-[#B22222] transition-colors shadow-inner">
       {icon}
     </div>
     <div className="text-center">
        <div className="text-lg font-black text-[#1A1A1A] serif-font">{label}</div>
        <div className="text-[8px] font-bold text-slate-300 uppercase tracking-widest mt-1">{sub}</div>
     </div>
  </button>
);

const ReaderAction = ({ icon, active, onClick }: any) => (
  <button onClick={onClick} className={`p-3 rounded-2xl transition-all border ${active ? 'bg-[#B22222] border-[#B22222] text-white shadow-lg' : 'bg-white border-[#e0d7c6] text-slate-300'}`}>
    {icon}
  </button>
);

const StatBox = ({ label, value }: any) => (
  <div className="bg-white border border-[#e0d7c6] px-6 py-4 rounded-2xl shadow-sm">
     <div className="text-[10px] font-black text-slate-300 uppercase mb-1">{label}</div>
     <div className="text-2xl font-black text-[#1A1A1A] serif-font">{value}</div>
  </div>
);

const Badge = ({ icon, label, active }: any) => (
  <div className={`flex flex-col items-center gap-4 p-8 rounded-[2rem] border-2 border-dashed transition-all ${active ? 'bg-white border-[#B22222]/20 shadow-lg' : 'bg-transparent border-slate-200 opacity-30 grayscale'}`}>
     <div className="text-4xl">{icon}</div>
     <div className="text-[10px] font-black text-slate-500 tracking-widest">{label}</div>
  </div>
);

export default ThreeCharacterApp;

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { 
  X, Play, Pause, ScrollText, ChevronRight, Sparkles, 
  RefreshCw, BookOpen, Volume2, SkipBack, SkipForward, 
  ArrowLeft, Search, Bookmark, History, LayoutGrid, 
  Library, Trophy, Target, Type, Mic2, FileText, 
  Compass, Feather, User, Menu, Sliders, Loader2, Star
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { SanZiJingVerse, CharAnalysis } from '../lib/sanzijingData';
import { GoogleGenAI } from "@google/genai";
import sql from '../lib/neon';

type ViewType = 'hub' | 'reader' | 'stories' | 'profile';

const ThreeCharacterApp: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const [verses, setVerses] = useState<SanZiJingVerse[]>([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [currentCharIdx, setCurrentCharIdx] = useState(-1);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentView, setCurrentView] = useState<ViewType>('hub');
  const [activeTab, setActiveTab] = useState<'study' | 'source' | 'lexicon' | 'ai'>('study');
  const [isLoading, setIsLoading] = useState(true);
  const [selectedCharDetail, setSelectedCharDetail] = useState<CharAnalysis | null>(null);
  const [aiInsight, setAiInsight] = useState<string>('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [showPinyin, setShowPinyin] = useState(true);
  const [isVertical, setIsVertical] = useState(true);
  const [stats, setStats] = useState({ learned: 124, streak: 5, points: 850 });

  const scrollRef = useRef<HTMLDivElement>(null);
  const verseRefs = useRef<(HTMLDivElement | null)[]>([]);

  // 语音播报
  const speak = (text: string, rate: number = 0.8) => {
    if (!window.speechSynthesis) return;
    window.speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(text);
    utterance.lang = 'zh-CN';
    utterance.rate = rate;
    window.speechSynthesis.speak(utterance);
  };

  const fetchData = useCallback(async () => {
    if (!sql) return;
    setIsLoading(true);
    try {
      const data = await sql`SELECT * FROM sanzijing_verses ORDER BY verse_index ASC`;
      if (data && data.length > 0) {
        const formatted = data.map(d => ({
          ...d,
          content_chars: Array.isArray(d.content_chars) ? d.content_chars : [],
          content_pinyin: Array.isArray(d.content_pinyin) ? d.content_pinyin : [],
          key_vocabulary: Array.isArray(d.key_vocabulary) ? d.key_vocabulary : [],
          tags: Array.isArray(d.tags) ? d.tags : [],
          char_analysis: typeof d.char_analysis === 'string' ? JSON.parse(d.char_analysis) : d.char_analysis
        })) as SanZiJingVerse[];
        setVerses(formatted);
      }
    } catch (e) {
      console.error("Fetch Error:", e);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => { fetchData(); }, [fetchData]);

  const fetchAiInsight = async (verse: SanZiJingVerse) => {
    if (isAiLoading || !verse) return;
    setIsAiLoading(true);
    try {
      // Fix: Follow @google/genai guidelines. Always use process.env.API_KEY directly.
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `你是一位温和的国学老师。请针对这段经文：“${verse.content_raw}”，给孩子写一段简短、有趣的生活建议。100字以内。`,
      });
      // Fix: Access response text using the property .text
      setAiInsight(response.text || '智慧正在生成中...');
    } catch (e) {
      setAiInsight('AI 老师去休息啦，待会再试吧。');
    } finally {
      setIsAiLoading(false);
    }
  };

  useEffect(() => {
    if (activeTab === 'ai' && !aiInsight && verses[currentIdx]) {
      fetchAiInsight(verses[currentIdx]);
    }
  }, [activeTab, currentIdx, verses]);

  const playVerseSequence = useCallback((idx: number) => {
    if (!window.speechSynthesis || !verses[idx]) return;
    window.speechSynthesis.cancel();
    const utterance = new SpeechSynthesisUtterance(verses[idx].content_raw);
    utterance.lang = 'zh-CN';
    utterance.rate = 0.75;

    utterance.onboundary = (e) => {
      const textBefore = verses[idx].content_raw.substring(0, e.charIndex);
      const chineseOnlyBefore = textBefore.replace(/[^\u4e00-\u9fa5]/g, '');
      setCurrentCharIdx(chineseOnlyBefore.length);
    };

    utterance.onend = () => {
      setCurrentCharIdx(-1);
      if (isPlaying && idx < verses.length - 1) {
        setTimeout(() => isPlaying && setCurrentIdx(idx + 1), 1000);
      } else {
        setIsPlaying(false);
      }
    };
    window.speechSynthesis.speak(utterance);
  }, [isPlaying, verses]);

  useEffect(() => {
    if (isPlaying) playVerseSequence(currentIdx);
    verseRefs.current[currentIdx]?.scrollIntoView({ behavior: 'smooth', block: 'center' });
    setAiInsight('');
  }, [currentIdx, isPlaying, playVerseSequence]);

  const activeVerse = verses[currentIdx];

  // 渲染分发
  const renderView = () => {
    switch (currentView) {
      case 'hub': return <HubView />;
      case 'reader': return <ReaderView />;
      case 'stories': return <StoriesView />;
      case 'profile': return <ProfileView />;
    }
  };

  // --- 视图组件: 首页枢纽 ---
  function HubView() {
    const dailyIdx = useMemo(() => new Date().getDate() % (verses.length || 1), []);
    const dailyVerse = verses[dailyIdx];

    return (
      <motion.div 
        initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
        className="flex-1 flex flex-col p-6 md:p-12 overflow-y-auto no-scrollbar"
      >
        <div className="flex justify-between items-start mb-12">
          <div>
             <h2 className="text-3xl md:text-5xl font-black text-[#1A1A1A] serif-font mb-2">晨诵 · 三字经</h2>
             <p className="text-slate-400 font-bold tracking-[0.2em] text-xs">温故而知新，可以为师矣。</p>
          </div>
          <div className="flex items-center gap-4">
             <div className="text-right">
                <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest">学习进度</div>
                <div className="text-lg font-black text-[#B22222]">85%</div>
             </div>
             <div className="w-12 h-12 bg-[#B22222] rounded-full flex items-center justify-center text-white shadow-xl shadow-[#B22222]/20">
                <User size={24} />
             </div>
          </div>
        </div>

        {/* 每日金句卡片 */}
        <div className="relative mb-12 group cursor-pointer" onClick={() => { setCurrentIdx(dailyIdx); setCurrentView('reader'); }}>
          <div className="absolute inset-0 bg-[#B22222]/5 rounded-[3rem] blur-3xl opacity-50 group-hover:opacity-100 transition-opacity" />
          <div className="relative bg-white/80 backdrop-blur-xl border border-[#e0d7c6] rounded-[2.5rem] md:rounded-[4rem] p-10 md:p-20 shadow-xl overflow-hidden">
             <div className="absolute top-10 right-10 opacity-[0.03] rotate-12 transition-transform duration-1000 group-hover:rotate-45">
                <Feather size={300} />
             </div>
             <div className="flex flex-col md:flex-row items-center gap-8 md:gap-16">
                <div className="flex flex-col items-center">
                   <div className="text-[10px] font-black text-[#B22222] bg-[#B22222]/10 px-3 py-1 rounded-full mb-6 tracking-widest">每日金句</div>
                   <div className="text-7xl md:text-9xl font-black text-[#1A1A1A] tracking-tighter serif-font leading-none">
                     {dailyVerse?.content_chars.slice(0, 3).join('')}
                   </div>
                </div>
                <div className="flex-1 text-center md:text-left">
                   <p className="text-xl md:text-3xl text-slate-600 leading-relaxed font-bold italic mb-8 serif-font">
                     “{dailyVerse?.translation_vernacular}”
                   </p>
                   <button className="px-8 py-3 bg-[#1A1A1A] text-white rounded-full text-xs font-black uppercase tracking-widest hover:bg-[#B22222] transition-all flex items-center gap-2 mx-auto md:mx-0">
                     开始研读 <ChevronRight size={16} />
                   </button>
                </div>
             </div>
          </div>
        </div>

        {/* 金刚区按钮 */}
        <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
           <HubCard icon={<BookOpen size={24}/>} label="全书阅读" sub="Immersive Read" onClick={() => setCurrentView('reader')} />
           <HubCard icon={<Compass size={24}/>} label="典故探索" sub="Historical Tales" onClick={() => setCurrentView('stories')} />
           <HubCard icon={<Trophy size={24}/>} label="成长印记" sub="Achievements" onClick={() => setCurrentView('profile')} />
           <HubCard icon={<RefreshCw size={24}/>} label="语音跟读" sub="Voice Practice" onClick={() => { setCurrentView('reader'); setIsPlaying(true); }} />
        </div>
      </motion.div>
    );
  }

  // --- 视图组件: 沉浸式阅读器 ---
  function ReaderView() {
    return (
      <motion.div initial={{ x: 50, opacity: 0 }} animate={{ x: 0, opacity: 1 }} className="flex-1 flex flex-col lg:flex-row overflow-hidden">
        {/* 左侧经文 */}
        <section className="flex-1 flex flex-col min-h-0 border-r border-[#e0d7c6] relative overflow-hidden bg-white/30">
          <div className="flex items-center justify-between p-6 shrink-0 z-20">
             <button onClick={() => setCurrentView('hub')} className="p-3 bg-white border border-[#e0d7c6] rounded-2xl text-slate-400 hover:text-[#B22222] transition-all shadow-sm">
                <ArrowLeft size={20} />
             </button>
             <div className="flex gap-2">
                <ReaderAction icon={<Type size={18}/>} active={showPinyin} onClick={() => setShowPinyin(!showPinyin)} />
                <ReaderAction icon={<LayoutGrid size={18}/>} active={isVertical} onClick={() => setIsVertical(!isVertical)} />
             </div>
          </div>

          <div className="flex-1 overflow-y-auto p-8 md:p-16 space-y-24 no-scrollbar scroll-smooth">
            {verses.map((v, i) => (
              <div 
                key={v.id} ref={el => { verseRefs.current[i] = el; }}
                onClick={() => { setIsPlaying(false); setCurrentIdx(i); speak(v.content_raw); }}
                className={`transition-all duration-700 cursor-pointer flex justify-center group ${currentIdx === i ? 'opacity-100' : 'opacity-10 blur-[0.5px] hover:opacity-40'}`}
              >
                <div className={`flex ${isVertical ? 'flex-row-reverse' : 'flex-col'} gap-8 md:gap-16 relative py-12 px-12 border-x border-[#B22222]/10`}>
                  <div className="absolute top-0 left-0 w-full h-px bg-[#B22222]/20" />
                  <div className="absolute bottom-0 left-0 w-full h-px bg-[#B22222]/20" />

                  {/* 分组显示 */}
                  <div className={`flex flex-wrap justify-center gap-x-12 md:gap-x-20 gap-y-12 max-w-[500px]`}>
                    {v.content_chars.map((char, cIdx) => (
                      <div key={cIdx} className="flex flex-col items-center">
                        {showPinyin && (
                          <span className={`text-[10px] md:text-sm font-mono mb-2 ${currentIdx === i && currentCharIdx === cIdx ? 'text-[#B22222] font-black' : 'text-slate-300'}`}>
                            {v.content_pinyin[cIdx]}
                          </span>
                        )}
                        <span className={`text-6xl md:text-[9rem] font-black leading-none transition-all serif-font ${currentIdx === i && currentCharIdx === cIdx ? 'text-[#1A1A1A] drop-shadow-2xl scale-110' : 'text-slate-200'}`}>
                          {char}
                        </span>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            ))}
            <div className="h-60" />
          </div>

          {/* 悬浮控制台 */}
          <div className="absolute bottom-10 left-1/2 -translate-x-1/2 z-40 w-[300px] md:w-[400px]">
            <div className="bg-[#1A1A1A]/90 backdrop-blur-2xl rounded-full p-2.5 flex items-center justify-between shadow-2xl border border-white/10">
               <button onClick={() => setCurrentIdx(prev => Math.max(0, prev - 1))} className="p-4 text-white/50 hover:text-white"><SkipBack size={24} fill="currentColor" /></button>
               <button onClick={() => setIsPlaying(!isPlaying)} className="w-16 h-16 bg-white rounded-full flex items-center justify-center shadow-lg active:scale-90 transition-all">
                 {isPlaying ? <Pause size={32} className="text-[#1A1A1A]" fill="currentColor" /> : <Play size={32} className="text-[#1A1A1A] ml-1" fill="currentColor" />}
               </button>
               <button onClick={() => setCurrentIdx(prev => Math.min(verses.length - 1, prev + 1))} className="p-4 text-white/50 hover:text-white"><SkipForward size={24} fill="currentColor" /></button>
            </div>
          </div>
        </section>

        {/* 右侧解析面板 */}
        <aside className="lg:w-[480px] xl:w-[560px] flex flex-col bg-white shadow-[-40px_0_100px_rgba(0,0,0,0.02)] z-30">
          <nav className="flex bg-[#FDFBF7] border-b border-[#e0d7c6]">
            {['study', 'source', 'lexicon', 'ai'].map((tab: any) => (
              <button
                key={tab} onClick={() => setActiveTab(tab)}
                className={`flex-1 py-6 flex flex-col items-center gap-1.5 text-[11px] font-black transition-all relative ${activeTab === tab ? 'text-[#B22222] bg-white' : 'text-slate-400 hover:bg-slate-50'}`}
              >
                {tab === 'study' ? <BookOpen size={16}/> : tab === 'source' ? <History size={16}/> : tab === 'lexicon' ? <Search size={16}/> : <Sparkles size={16}/>}
                {tab === 'study' ? '义理' : tab === 'source' ? '典故' : tab === 'lexicon' ? '字解' : 'AI'}
                {activeTab === tab && <motion.div layoutId="tab-active" className="absolute bottom-0 w-full h-1 bg-[#B22222]" />}
              </button>
            ))}
          </nav>

          <div className="flex-1 overflow-y-auto p-8 md:p-12 space-y-12 no-scrollbar">
            <AnimatePresence mode="wait">
              {activeTab === 'study' && (
                <motion.div key="study" initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} className="space-y-12">
                   <section>
                      <h3 className="text-[10px] font-black text-slate-300 uppercase tracking-widest mb-6 italic serif-font">现代译文</h3>
                      <p className="text-3xl font-black text-[#1A1A1A] leading-tight italic serif-font">“{activeVerse?.translation_vernacular}”</p>
                   </section>
                   <section className="bg-[#f9f6f0] p-8 rounded-[2rem] border border-[#e0d7c6] shadow-sm">
                      <h3 className="text-[10px] font-black text-[#B22222] uppercase tracking-[0.3em] mb-8 italic">深度导读</h3>
                      <p className="text-lg text-slate-600 leading-loose font-medium text-justify">
                        {activeVerse?.interpretation_deep}
                      </p>
                   </section>
                </motion.div>
              )}
              {activeTab === 'ai' && (
                <motion.div key="ai" initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="space-y-8">
                   <div className="p-10 bg-emerald-50/50 border border-emerald-100 rounded-[3.5rem] relative overflow-hidden shadow-sm">
                      <div className="flex items-center justify-between mb-10 text-emerald-600">
                        <div className="flex items-center gap-4"><Mic2 size={24} /> <h4 className="text-[10px] font-black uppercase tracking-[0.5em] italic">AI 老师的生活智慧</h4></div>
                      </div>
                      {isAiLoading ? (
                        <div className="py-20 flex flex-col items-center gap-6">
                          {/* Fix: Added Loader2 to lucide-react imports */}
                          <Loader2 className="w-12 h-12 text-emerald-500 animate-spin" />
                          <p className="text-[10px] text-emerald-400 font-black tracking-[0.3em]">AI 正在查阅古籍...</p>
                        </div>
                      ) : (
                        <div className="animate-in fade-in duration-1000">
                           <p className="text-3xl font-bold text-emerald-900 leading-snug italic mb-12 serif-font">“{aiInsight}”</p>
                           <div className="bg-emerald-900 text-white p-8 rounded-3xl flex items-center gap-6 shadow-2xl">
                              <Target size={32} className="text-emerald-300 shrink-0" />
                              <p className="text-sm font-medium leading-relaxed opacity-90 italic">这是专门为你准备的今日建议，记得在生活中尝试一下哦！</p>
                           </div>
                        </div>
                      )}
                   </div>
                </motion.div>
              )}
              {/* 其他 Tab 渲染逻辑在此添加 */}
            </AnimatePresence>
          </div>
        </aside>
      </motion.div>
    );
  }

  // --- 视图组件: 典故探索 ---
  function StoriesView() {
    return (
      <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="flex-1 p-6 md:p-12 overflow-y-auto no-scrollbar">
         <div className="flex items-center gap-6 mb-12">
            <button onClick={() => setCurrentView('hub')} className="p-3 bg-white border border-[#e0d7c6] rounded-2xl"><ArrowLeft/></button>
            <h2 className="text-4xl font-black serif-font text-[#1A1A1A]">典故汇编</h2>
         </div>
         <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {verses.filter(v => v.allusion_title).map(v => (
              <div key={v.id} className="bg-white border border-[#e0d7c6] rounded-[2.5rem] p-8 hover:shadow-2xl transition-all cursor-pointer group">
                 <div className="flex justify-between items-start mb-6">
                    <div className="px-4 py-1 bg-[#B22222]/5 text-[#B22222] rounded-full text-[10px] font-black">{v.allusion_source}</div>
                    {/* Fix: Added Star to lucide-react imports */}
                    <Star size={16} className="text-slate-200 group-hover:text-amber-400 transition-colors" />
                 </div>
                 <h3 className="text-2xl font-black text-[#1A1A1A] mb-4 serif-font group-hover:text-[#B22222] transition-colors">{v.allusion_title}</h3>
                 <p className="text-slate-500 text-sm leading-relaxed italic mb-8 line-clamp-3">“{v.allusion_context}”</p>
                 <div className="pt-6 border-t border-[#f3efe6] flex justify-between items-center opacity-0 group-hover:opacity-100 transition-opacity">
                    <span className="text-[10px] font-black uppercase tracking-widest text-[#B22222]">阅读全文</span>
                    <ChevronRight size={16} className="text-[#B22222]" />
                 </div>
              </div>
            ))}
         </div>
      </motion.div>
    );
  }

  // --- 视图组件: 个人成就 ---
  function ProfileView() {
    return (
      <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="flex-1 p-6 md:p-12 overflow-y-auto no-scrollbar">
         <button onClick={() => setCurrentView('hub')} className="mb-8 p-3 bg-white border border-[#e0d7c6] rounded-2xl"><ArrowLeft/></button>
         <div className="max-w-4xl mx-auto">
            <div className="flex flex-col md:flex-row items-center gap-10 mb-16">
               <div className="w-32 h-32 bg-[#1A1A1A] rounded-full flex items-center justify-center text-white text-5xl font-black shadow-2xl">修</div>
               <div className="text-center md:text-left flex-1">
                  <h2 className="text-4xl font-black serif-font mb-2">学而时习之</h2>
                  <p className="text-slate-400 font-bold italic">已在知识通国学馆修行 {stats.streak} 日</p>
               </div>
               <div className="grid grid-cols-3 gap-6">
                  <StatBox label="已学汉字" value={stats.learned} />
                  <StatBox label="连续打卡" value={stats.streak} />
                  <StatBox label="国学积分" value={stats.points} />
               </div>
            </div>

            <h3 className="text-xl font-black serif-font mb-8 border-b border-[#e0d7c6] pb-4">勋章墙</h3>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
               <Badge icon="🖋️" label="笔耕不辍" />
               <Badge icon="墨" label="墨韵留芳" active />
               <Badge icon="📜" label="博闻强识" active />
               <Badge icon="砚" label="铁杵磨针" />
            </div>
         </div>
      </motion.div>
    );
  }

  return (
    <div className="fixed inset-0 z-[60] bg-[#F9F6F0] flex flex-col font-serif select-none overflow-hidden pb-[env(safe-area-inset-bottom)]">
      <div className="absolute inset-0 opacity-[0.06] pointer-events-none z-0 bg-[url('https://www.transparenttextures.com/patterns/rice-paper.png')]" />

      <AnimatePresence mode="wait">
        {renderView()}
      </AnimatePresence>

      {isLoading && (
        <div className="fixed inset-0 z-[100] bg-[#F9F6F0] flex flex-col items-center justify-center">
          {/* Fix: Added Loader2 to lucide-react imports */}
          <Loader2 className="w-12 h-12 text-[#B22222] animate-spin mb-4" />
          <p className="text-xs font-black tracking-[0.4em] text-[#B22222] uppercase">开启全息经文长卷...</p>
        </div>
      )}

      <style>{`
        .serif-font { font-family: 'Noto Serif SC', serif; }
        .no-scrollbar::-webkit-scrollbar { display: none; }
      `}</style>
    </div>
  );
};

const HubCard = ({ icon, label, sub, onClick }: any) => (
  <button onClick={onClick} className="bg-white border border-[#e0d7c6] p-8 rounded-[2.5rem] flex flex-col items-center gap-4 hover:border-[#B22222] hover:shadow-xl transition-all group">
     <div className="w-16 h-16 bg-[#f9f6f0] rounded-2xl flex items-center justify-center text-slate-400 group-hover:text-[#B22222] transition-colors shadow-inner">
       {icon}
     </div>
     <div className="text-center">
        <div className="text-lg font-black text-[#1A1A1A] serif-font">{label}</div>
        <div className="text-[8px] font-bold text-slate-300 uppercase tracking-widest mt-1">{sub}</div>
     </div>
  </button>
);

const ReaderAction = ({ icon, active, onClick }: any) => (
  <button onClick={onClick} className={`p-3 rounded-2xl transition-all border ${active ? 'bg-[#B22222] border-[#B22222] text-white shadow-lg' : 'bg-white border-[#e0d7c6] text-slate-300'}`}>
    {icon}
  </button>
);

const StatBox = ({ label, value }: any) => (
  <div className="bg-white border border-[#e0d7c6] px-6 py-4 rounded-2xl shadow-sm">
     <div className="text-[10px] font-black text-slate-300 uppercase mb-1">{label}</div>
     <div className="text-2xl font-black text-[#1A1A1A] serif-font">{value}</div>
  </div>
);

const Badge = ({ icon, label, active }: any) => (
  <div className={`flex flex-col items-center gap-4 p-8 rounded-[2rem] border-2 border-dashed transition-all ${active ? 'bg-white border-[#B22222]/20 shadow-lg' : 'bg-transparent border-slate-200 opacity-30 grayscale'}`}>
     <div className="text-4xl">{icon}</div>
     <div className="text-[10px] font-black text-slate-500 tracking-widest">{label}</div>
  </div>
);

export default ThreeCharacterApp;
